  ('Sofitel Guangzhou Sunrich',    'Guangzhou', 23.1310, 113.3300, 'Club Millésime · 22–24 May'),
  ('Swissôtel Grand Shanghai',     'Shanghai',  31.2360, 121.4560, '25–28 May · after the North Bund mis-sell'),
  ('Fairmont Beijing',             'Beijing',   39.9100, 116.4610, 'Fairmont Gold · 28–30 May'),
  ('Hilton Beijing Capital Airport','Beijing',  40.0600, 116.6000, 'Airline staff rate · 30–31 May'),
  ('ANA InterContinental Tokyo',   'Tokyo',     35.6690, 139.7400, 'High-floor king, staff rate · 31 May'),
  ('Hilton Tokyo',                 'Tokyo',     35.6910, 139.6920, 'Shinjuku · 1 Jun'),
  ('Mercure Tokyo Hibiya',         'Tokyo',     35.6730, 139.7590, 'Next to Dover Street Market Ginza · 2 Jun'),
  ('Villa Fontaine Grand Haneda',  'Tokyo',     35.5490, 139.7900, 'Inside HND · 3 Jun'),
  ('Sofitel Sydney Wentworth',     'Sydney',   -33.8660, 151.2100, 'The Rocks / Martin Place · 4–7 Jun')
) as v(label, city, lat, lon, notes)
where slug='china-japan';
